import gc
import time
from prometheus_client import Histogram

GC_PAUSE = Histogram('python_gc_pause_seconds', 'GC pause duration', ['generation'])

def gc_callback(phase, info):
    if phase == 'stop':
        gen = info['generation']
        elapsed = time.perf_counter() - _gc_start.get(gen, 0)
        GC_PAUSE.labels(generation=str(gen)).observe(elapsed)

_gc_start = {}

def gc_start_callback(phase, info):
    if phase == 'start':
        _gc_start[info['generation']] = time.perf_counter()

gc.callbacks.append(gc_start_callback)
gc.callbacks.append(gc_callback)

from importlib.metadata import metadata

def audit_package(name: str) -> dict:
    meta = metadata(name)
    classifiers = meta.get_all("Classifier") or []
    stability = [
        c.split(" :: ")[-1]
        for c in classifiers
        if "Development Status" in c
    ]
    return {
        "name": meta["Name"],
        "version": meta["Version"],
        "stability": stability[0] if stability else "unknown",
        "requires_python": meta.get("Requires-Python", "unspecified"),
        "license": meta.get("License", "unknown"),
    }

print(audit_package("numpy"))   # {'stability': '5 - Production/Stable', ...}
print(audit_package("requests")) # {'stability': '5 - Production/Stable', ...}
